sql:
SELECT report_name, report_date, generated_by, COUNT(report_data) AS entry_count
FROM kpi_reports
GROUP BY report_name, report_date, generated_by;

external_knowledge:
- 'top diseases that frequently appear with other diseases' refers to the top 3 co-occurring diseases for any other disease, based on the co-occurrence rate;
- 'most prevalent diseases that co-occur with other diseases' refers to the diseases with the highest prevalence rates that are also among the top co-occurring diseases;
- 'the user who generated the report' refers to the user who logged in on '2023-05-01'.

sql:
SELECT AVG(co_occurrence_rate) AS average_co_occurrence_rate
FROM co_occurrences
WHERE disease1_id = 0 AND disease2_id = 0;

SELECT MAX(kpi_value) AS max_disease_co_occurrence_rate
FROM kpi_values
WHERE kpi_id = 0;

SELECT AVG(kpi_value) AS avg_kpi_value
FROM kpi_values
WHERE kpi_date LIKE '2023-05-%';

SELECT report_name
FROM kpi_reports
WHERE generated_by = 'Alice Johnson';

SELECT disease_name
FROM diseases
WHERE prevalence_rate = (
  SELECT MAX(prevalence_rate) FROM diseases
);

SELECT kpi_date, kpi_value
FROM kpi_values
ORDER BY kpi_date DESC;
